2655 Instruction *InstCombinerImpl::foldAndOrOfSelectUsingImpliedCond(Value *Op,
2656                                                                  SelectInst &SI,
2657                                                                  bool IsAnd) {
2658   Value *CondVal = SI.getCondition();
2659   Value *A = SI.getTrueValue();
2660   Value *B = SI.getFalseValue();
2661 
2662   assert(Op->getType()->isIntOrIntVectorTy(1) &&
2663          "Op must be either i1 or vector of i1.");
2664 
2665   std::optional<bool> Res = isImpliedCondition(Op, CondVal, DL, IsAnd);
2666   if (!Res)
2667     return nullptr;
2668 
2669   Value *Zero = Constant::getNullValue(A->getType());
2670   Value *One = Constant::getAllOnesValue(A->getType());
2671 
2672   if (*Res == true) {
2673     if (IsAnd)
2674       // select op, (select cond, A, B), false => select op, A, false
2675       // and    op, (select cond, A, B)        => select op, A, false
2676       //   if op = true implies condval = true.
2677       return SelectInst::Create(Op, A, Zero);
2678     else
2679       // select op, true, (select cond, A, B) => select op, true, A
2680       // or     op, (select cond, A, B)       => select op, true, A
2681       //   if op = false implies condval = true.
2682       return SelectInst::Create(Op, One, A);
2683   } else {
2684     if (IsAnd)
2685       // select op, (select cond, A, B), false => select op, B, false
2686       // and    op, (select cond, A, B)        => select op, B, false
2687       //   if op = true implies condval = false.
2688       return SelectInst::Create(Op, B, Zero);
2689     else
2690       // select op, true, (select cond, A, B) => select op, true, B
2691       // or     op, (select cond, A, B)       => select op, true, B
2692       //   if op = false implies condval = false.
2693       return SelectInst::Create(Op, One, B);
2694   }
2695 }
